
public class HelloWorld {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		// 자바 파일을 만들때는 src 폴더에서 class메뉴를 누르면 된다.
		// 주석(메모)
		
		// 개발자만 보는 창 콘솔 console.log()
		// 자바에서는 System.out.println(); 이걸로 변경된다.
		
		System.out.println("안녕하세요");
		System.out.println("실행은 단축키 사용이 편하다");
		System.out.println(1);
		
		// 단축키 syso + ctrl + space
		System.out.println(1+1);
		System.out.println(10.1+2);
		
		
		// 실행
		// 1. 메뉴 초록색 재생버튼 클릭!
		// 2. 단축키 ctrl + F11 (저장 + 자바프로그램 실행)
		// 자바는 실시간 기능이 없어서 무조건 ctrl + f11
		
	} // main이 끝나는 중괄호 안에 코드를 작성해야 된다.

}
